INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'chicago'), 'RS-3', 'rs-3', 'Residential Single-Unit (Detached House) District', 'Primarily for detached single-family homes, with provisions for two-flats under specific conditions, maintaining the character of single-unit neighborhoods.', 30, 0.9, 2500, NULL, 20, 35, 5, '2 spaces per unit for detached houses; 1.5 spaces per unit for two-flats, with exemptions for lots 33 feet or less in width without alley access.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rs-3' AND z.city_id = (SELECT id FROM cities WHERE slug = 'chicago') AND pu.name IN ('Detached House', 'Two-flat (conditional)') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'chicago'), 'RT4', 'rt4', 'Residential Two-Flat, Townhouse and Multi-Unit District', 'Accommodates detached houses, two-flats, townhouses, and low-density multi-unit residential buildings, providing a transition between single-unit and higher-density residential districts.', 38, 1.2, 1000, NULL, 15, NULL, NULL, '1 space per unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rt4' AND z.city_id = (SELECT id FROM cities WHERE slug = 'chicago') AND pu.name IN ('Detached House', 'Two-flat', 'Townhouse', 'Low-density multi-unit residential') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'chicago'), 'RM-5', 'rm-5', 'Residential Multi-Unit District', 'Intended for moderate- to high-density multi-unit residential buildings, including detached houses, two-flats, and townhouses, in areas where such development exists or is desired.', 45, 2, 400, NULL, 15, NULL, NULL, '1 space per unit.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
INSERT INTO zone_permitted_uses (zone_id, permitted_use_id) SELECT z.id, pu.id FROM zones z, permitted_uses pu WHERE z.zone_code_slug = 'rm-5' AND z.city_id = (SELECT id FROM cities WHERE slug = 'chicago') AND pu.name IN ('Detached House', 'Two-flat', 'Townhouse', 'Multi-unit residential building') ON CONFLICT DO NOTHING;
INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'chicago'), 'B1-2', 'b1-2', 'Neighborhood Shopping District', 'Designed for a broad range of small-scale retail and service uses, often embedded in residential neighborhoods. Setbacks are generally not required unless abutting a residential district.', 38, 2.2, 1000, NULL, NULL, NULL, NULL, 'Typically ranges from 2.5 to 5 spaces per 1,000 square feet of floor area, varying by B classification and store size.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
