INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'chicago'), 'B3-3', 'b3-3', 'Community Shopping District', 'The most permissive retail district, accommodating shopping centers and larger buildings, with provisions for dwelling units. Setbacks are generally not required unless abutting a residential district.', NULL, 3, 400, NULL, NULL, NULL, NULL, 'Typically ranges from 2.5 to 5 spaces per 1,000 square feet of floor area, varying by B classification and store size.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
