INSERT INTO zones (city_id, zone_code, zone_code_slug, zone_name, description, max_height_ft, far, min_lot_size_sqft, max_impervious_cover_pct, setback_front_ft, setback_rear_ft, setback_side_ft, parking_requirement) VALUES ((SELECT id FROM cities WHERE slug = 'chicago'), 'M1-2', 'm1-2', 'Limited Manufacturing/Business Park District', 'Intended for low-impact manufacturing, wholesaling, warehousing, and distribution activities primarily within enclosed buildings, promoting high-quality industrial development. Setbacks are generally not required, with exceptions for industrial parks and business parks.', NULL, 2.2, NULL, NULL, NULL, NULL, NULL, 'Off-street parking regulations are detailed in Chapter 17-10 of the Zoning Ordinance.') ON CONFLICT (city_id, zone_code_slug) DO UPDATE SET zone_name = excluded.zone_name, description = excluded.description, max_height_ft = excluded.max_height_ft, far = excluded.far, min_lot_size_sqft = excluded.min_lot_size_sqft, max_impervious_cover_pct = excluded.max_impervious_cover_pct, setback_front_ft = excluded.setback_front_ft, setback_rear_ft = excluded.setback_rear_ft, setback_side_ft = excluded.setback_side_ft, parking_requirement = excluded.parking_requirement;
